  `id` VARCHAR(5) NOT NULL,
  `name` VARCHAR(45) NOT NULL,
  `description` VARCHAR(255) NULL,
  `customer_effect` TINYINT NULL COMMENT '1 = increase accounts receivable\n0 = no effect\n-1 = decrease accounts receivable',
  `supplier_effect` TINYINT NULL COMMENT '1 = increase accounts payable\n0 = no effect\n-1 = decrease accounts payable',
  `stock_effect` TINYINT NULL COMMENT '1 = increase inventory\n0 = no effect\n-1 = decrease inventory',
  `membership_effect` TINYINT NULL,
  `backflush_effect` TINYINT NULL COMMENT '1 = increase child inventory\n0 = no effect\n-1 = decrease child inventory',
  `gl_effect` TINYINT NULL COMMENT '1 = credit account\n0 = no effect\n-1 = debit account',
  `created_at` TIMESTAMP NULL,
  `updated_at` TIMESTAMP NULL,
  PRIMARY KEY (`id`),
  UNIQUE INDEX `id_UNIQUE` (`id` ASC) VISIBLE);


