-- -----------------------------------------------------
DROP TABLE IF EXISTS `1office_0_2`.`forecast` ;

CREATE TABLE IF NOT EXISTS `1office_0_2`.`forecast` (
  `id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
