-- -----------------------------------------------------
-- Table `1office_0_2`.`frozen_forecast`
-- -----------------------------------------------------
DROP TABLE IF EXISTS `1office_0_2`.`frozen_forecast` ;

CREATE TABLE IF NOT EXISTS `1office_0_2`.`frozen_forecast` (
  `id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
  `customer_id` BIGINT UNSIGNED NOT NULL,
  `item_id` BIGINT UNSIGNED NOT NULL,
  `warehouse_id` BIGINT UNSIGNED NOT NULL,
  `bu_id` BIGINT UNSIGNED NOT NULL,
  `forecast_year` INT(5) NULL,
  `forecast_month` INT(3) NULL,
  `forecast_type` VARCHAR(1) NULL COMMENT 'F = Forecast, A = Actual, B = Budget, E = Future Estimate, H = Historic Estimate, S = Saved forecast of a user',
  `quantity_calc` DECIMAL(20,3) NULL COMMENT 'Calculated forecast quantity; if 0 then no historic data for calculation',
  `q_uom_id` INT UNSIGNED NOT NULL COMMENT 'The unit of measure for the quantity',
  `seasonality_calc` DECIMAL(6,3) NULL COMMENT 'seasonality factor calculated',
  `growth_rate_calc` DECIMAL(6,3) NULL COMMENT 'calculated growth rate',
  `price_calc` DECIMAL(20,5) NULL,
  `p_uom_id` INT UNSIGNED NOT NULL,
  `last_update_users_id` BIGINT UNSIGNED NULL COMMENT 'The last user that updated the forecast',
  `last_updated_at` TIMESTAMP NULL,
  `quantity` DECIMAL(20,3) NULL COMMENT 'changed forecast quantity, default is equal to calc forecast = result of annual and season and growth',
  `seasonality` DECIMAL(6,3) NULL COMMENT 'entered seasonality = default to calc -> used for calc',
  `growth_rate` DECIMAL(6,3) NULL COMMENT 'growth rate = default to calc rate -> applied in calculation',
  `price` DECIMAL(20,5) NULL,
  `created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` TIMESTAMP NULL,
  PRIMARY KEY (`id`),
  UNIQUE INDEX `id_UNIQUE` (`id` ASC) VISIBLE,
  INDEX `fk_forecast_customer1_idx` (`customer_id` ASC) VISIBLE,
  INDEX `fk_forecast_item1_idx` (`item_id` ASC) VISIBLE,
  INDEX `fk_forecast_warehouse1_idx` (`warehouse_id` ASC) VISIBLE,
  INDEX `fk_forecast_users1_idx` (`last_update_users_id` ASC) VISIBLE,
  INDEX `fk_forecast_bu1_idx` (`bu_id` ASC) VISIBLE,
  INDEX `fk_forecast_uom1_idx` (`q_uom_id` ASC) VISIBLE,
