  CONSTRAINT `fk_forecast_customer10`
    FOREIGN KEY (`customer_id`)
    REFERENCES `1office_0_2`.`customer` (`id`)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION,
  CONSTRAINT `fk_forecast_item10`
    FOREIGN KEY (`item_id`)
    REFERENCES `1office_0_2`.`item` (`id`)
    ON DELETE NO ACTION
    ON UPDATE NO ACTION,
  CONSTRAINT `fk_forecast_warehouse10`
