-- -----------------------------------------------------
-- Data for table `1office_0_2`.`inco_terms`
-- -----------------------------------------------------
START TRANSACTION;
USE `1office_0_2`;
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (1, 'EXW', 'EXW - Ex Works', 2020, NULL, 'EXW – Ex Works (named place of delivery) - Any mode of transport.  Ex works is when the seller places the goods at the disposal of the buyer at the seller’s premises or at another named place (i.e., works, factory, warehouse, etc.).  The seller does not need to load the goods on any collecting vehicle. Nor does it need to clear them for export, where such clearance is applicable.', 'Any mode(s) of transport', 'Buyer collect and pay', 'At buyers disposal', 'Seller arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Negotiable', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (2, 'FCA', 'FCA – Free Carrier', 2020, NULL, 'FCA – Free Carrier (named place of delivery) - Any mode of transport.  The seller delivers the goods to the carrier or another person nominated by the buyer at the seller’s premises or another named place.  The parties are well advised to specify as explicitly as possible the point within the named place of delivery, as the risk passes to the buyer at that point.  2020 Update: Allows for the issuance of a Bill of Lading with an onboard notation.  (Allows buyers to request an onboard bill of lading for containerized goods.)', 'Any mode(s) of transport', 'Buyer collect and pay', 'On buyers transport', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Negotiable', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (3, 'CPT', 'CPT – Carriage Paid To', 2020, NULL, 'CPT – Carriage Paid To (named place of destination) - Any mode of transport.  The seller delivers the goods to the carrier or another person nominated by the seller at an agreed place (if any such site is agreed between parties).  The seller must contract for and pay the costs of carriage necessary to bring the goods to the named place of destination.', 'Any mode(s) of transport', 'Seller arrange and pay', 'At carrier', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Negotiable', 'Seller arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (4, 'CIP', 'CIP – Carriage and Insurance Paid to', 2020, NULL, 'CIP – Carriage and Insurance Paid to (named place of destination) - Any mode of transport.  The seller has the same responsibilities as CPT, but they also contract for insurance cover against the buyer’s risk of loss of or damage to the goods during the carriage.  The buyer should note that under CIP the seller is required to obtain insurance only on minimum cover. Should the buyer wish to have more insurance protection, it will need either to agree as much expressly with the seller or to make its own extra insurance arrangements.  2020 update:  Requires comprehensive insurance (Clause A - [All risk, subject to itemized exclusions]) instead of minimal insurance (Clause C - [Number of listed risks, subject to itemized exclusions]).', 'Any mode(s) of transport', 'Seller arrange and pay', 'At carrier', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (5, 'DPU', 'DPU – Delivered At Place Unloaded', 2020, NULL, 'DPU – Delivered At Place Unloaded (named place of destination) - Any mode of tansport.  DPU is a new Incoterm rule that replaces the former Incoterm DAT (Delivered At Terminal).  The seller delivers when the goods are unloaded and placed at the disposal of the buyer at a named place of destination.  The seller bears all risks involved in bringing the goods to, and unloading them at the named place of destination.', 'Any mode(s) of transport', 'Seller arrange and pay', 'At named place', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Negotiable', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Buyer arrange and pay', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (6, 'DAP', 'DAP – Delivered At Place', 2020, NULL, 'DAP – Delivered At Place (named place of destination) - Any mode of transport.  The seller delivers when the goods are placed at the disposal of the buyer on the arriving means of transport ready for unloading at the named place of destination.  The seller bears all risks involved in bringing the goods to the named place.  2020 update: Replaced DAT to remove confusion about the term “terminal.”', 'Any mode(s) of transport', 'Seller arrange and pay', 'At named place - unloaded', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Negotiable', 'Seller arrange and pay', 'Seller arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (7, 'DDP', 'DDP – Delivered Duty Paid', 2020, NULL, 'DDP – Delivered Duty Paid (named place of destination) - Any mode of transport.  The seller delivers the goods when the goods are placed at the disposal of the buyer, cleared for import on the arriving means of transport ready for unloading at the named place of destination.  The seller bears all the costs and risks involved in bringing the goods to the place of destination. They must clear the products not only for export but also for import, to pay any duty for both export and import and to carry out all customs formalities.  Under DDP, the seller pays for all shipping costs, including import customs clearance, import duties & taxes, and any additional charges involved in delivering the goods to the named place of destination.', 'Any mode(s) of transport', 'Seller arrange and pay', 'At named place', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Negotiable', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (8, 'FAS', 'FAS – Free Alongside Ship', 2020, NULL, 'FAS – Free Alongside Ship (named port of shipment) - Sea and inland waterways transport.  The seller delivers when the goods are placed alongside the vessel (e.g., on a quay or a barge) nominated by the buyer at the named port of shipment.  The risk of loss of or damage to the goods passes when the products are alongside the ship.  The buyer bears all costs from that moment onwards.', 'Sea and Inland waterway transport', 'Buyer collect and pay', 'Alongside ship', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Negotiable', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (9, 'FOB', 'FOB – Free on Board', 2020, NULL, 'FOB – Free on Board (named port of shipment) - Sea and inland waterways transport.  The seller delivers the goods on board the vessel nominated by the buyer at the named port of shipment or procures the goods already so delivered.  The buyer becomes responsible for bearing all costs and risks from the moment the goods are on board the vessel, so the buyer will pay for the International transportation, insurance, and any further costs.  Seller’s costs include delivering the goods to the port of shipment, loading costs onto the vessel, and export duties, taxes, and customs clearance.  Buyer covers costs including main carriage (freight) costs from the port of loading to the port of destination, unloading costs at the destination port, and import duties, taxes, and customs clearance at the destination country.', 'Sea and Inland waterway transport', 'Buyer collect and pay', 'On board vessel', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Buyer arrange and pay', 'Negotiable', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (10, 'CFR', 'CFR – Cost and Freight', 2020, NULL, 'CFR – Cost and Freight (named port of destination) - Sea and inland waterways transport.  The seller delivers the goods on board the vessel or procures the goods already so delivered.  The risk of loss of or damage to the goods passes when the products are on board the vessel.  The seller must contract for and pay the costs and freight necessary to bring the goods to the named port of destination.', 'Sea and Inland waterway transport', 'Seller arrange and pay', 'On board vessel', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Negotiable', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (11, 'CIF', 'CIF – Cost, Insurance & Freight', 2020, NULL, 'CIF – Cost, Insurance & Freight (named port of destination) - Sea and inland waterways transport.  The seller delivers the goods on board the vessel or procures the goods already so delivered. The risk of loss of or damage to the goods passes when the products are on the ship.  The seller must contract for and pay the costs and freight necessary to bring the goods to the named port of destination.  The seller also contracts for insurance cover against the buyer’s risk of loss of or damage to the goods during the carriage.  The buyer should note that under CIF the seller is required to obtain insurance only on minimum cover. Should the buyer wish to have more insurance protection, it will need either to agree as much expressly with the seller or to make its own extra insurance arrangements.  2020 update: Insurance requirements remain minimal (Clause C - [Number of listed risks, subject to itemized exclusions]).', 'Sea and Inland waterway transport', 'Seller arrange and pay', 'On board vessel', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Seller arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', 'Buyer arrange and pay', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (12, 'DAF', 'DAF – Delivered at Frontier', 2000, 'DAT', 'DAF – Delivered at Frontier (named place of delivery) - Any mode of transport.  It can be used when the goods are transported by rail and road. The seller pays for transportation to the named place of delivery at the frontier. The buyer arranges for customs clearance and pays for transportation from the frontier to his factory. The passing of risk occurs at the frontier.', 'Any mode(s) of transport', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (13, 'DAT', 'DAT – Delivered at Terminal', 2010, 'DPU', 'DAT – Delivered at Terminal (named terminal) - Any mode of transport.  Delivered at Terminal: Seller bears cost, risk and responsibility until goods are unloaded (delivered) at named quay, warehouse, yard, or terminal at destination. Demurrage or detention charges may apply to seller. Seller clears goods for export, not import. DAT replaces DEQ, DES.  2020 update: Renamed to DPU (Delivered at Place Unloaded) to allow delivery at any place, not just a terminal.', 'Any mode(s) of transport', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (14, 'DES', 'DES – Delivered Ex Ship', 2000, 'DAT', 'DES – Delivered Ex Ship (named port of destination) - Sea and inland waterways transport.  It means that the seller has to pay for the same as in CIF, but the passing of risk does not occur until the ship has arrived at the port of destination, but before the goods have been unloaded.', 'Sea and Inland waterway transport', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (15, 'DEQ', 'DEQ – Delivered Ex Quay', 2000, 'DAT', 'DEQ – Delivered Ex Quay (named port of delivery) - Sea and inland waterways transport.  It means the same as DES, but the passing of risk does not occur until the goods have been unloaded at the port of destination.', 'Sea and Inland waterway transport', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (16, 'DDU', 'DDU – Delivered Duty Unpaid', 2000, 'DAP', 'DDU – Delivered Duty Unpaid (named place of destination) - Any mode of transport.  \"Delivered Duty Unpaid\" means that the seller delivers the goods to the buyer, not cleared for import, and\r not unloaded from arriving means of transport at the named place of destination. The seller has to bear the costs and risks involved in bringing the goods thereto, other than, where applicable, any \"duty\" (which term includes the responsibility for and the risks of the carrying out of customs formalities, and the payment of customs duties, taxes and other charges) for import in the country of destination.', 'Any mode(s) of transport', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (17, 'FOR', 'FOR - Free on rail', 1980, 'FCA', 'FOR - Free on rail (named place of destination) - Any mode of transport', 'Any mode(s) of transport', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`inco_terms` (`id`, `abreviation`, `name`, `year`, `replaced_by`, `description`, `transport_type`, `freight_terms`, `transfer_of_risk`, `export_packaging`, `loading_cost`, `delivery_port_place`, `export_duty_taxes_customs_clearance`, `origin_terminal_charges`, `loading_on_carriage`, `carriage_charges`, `insurance`, `destination_terminal_charges`, `delivery_to_destination`, `unloading_at_destination`, `import_duty_taxes_customs_clearance`, `created_at`, `updated_at`) VALUES (18, 'FOT', 'FOT - Free on truck', 1980, 'FCA', 'FOT - Free on truc (named place of destination) - Any mode of transport', 'Any mode(s) of transport', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2000-01-01 00:00:00', '2000-01-01 00:00:00');

COMMIT;


