-- -----------------------------------------------------
-- Data for table `1office_0_2`.`bpmn_event`
-- -----------------------------------------------------
START TRANSACTION;
USE `1office_0_2`;
INSERT INTO `1office_0_2`.`bpmn_event` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (1, 'Message', 'Triggers the process, facilitates intermediate processes, or finishes the process.', '2020-01-01 00:00:00', '2020-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_event` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (2, 'Timer', 'A time, date, or recurring time and date triggers the process, aids intermediates processes, or completes the process.', '2020-01-01 00:00:00', '2020-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_event` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (3, 'Escalation', 'A step reacts on an escalation and flows to another role in the organization. This event is only used within an event sub-process. An escalation occurs when someone at a higher level of responsibility within the organization becomes involved in a process.', '2020-01-01 00:00:00', '2020-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_event` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (4, 'Condition', 'A process begins or continues when a business condition or business rule is met.', '2020-01-01 00:00:00', '2020-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_event` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (5, 'Link', 'A sub-process that is part of a larger process.', '2020-01-01 00:00:00', '2020-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_event` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (6, 'Error', 'A caught error at the start, middle, or end of a process. An event sub-process with an error trigger will always interrupt its containing process.', '2020-01-01 00:00:00', '2020-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_event` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (7, 'Cancel', 'Reacts on a transaction that was canceled within a sub-process. In an end event, the cancel symbol represents the triggered cancellation of a process.', '2020-01-01 00:00:00', '2020-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_event` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (8, 'Compensation', 'A refund that’s triggered when operations partially fail.', '2020-01-01 00:00:00', '2020-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_event` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (9, 'Signal', 'A signal that communicates across different processes. A signal symbol can begin a process, facilitate it, or complete it.', '2020-01-01 00:00:00', '2020-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_event` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (10, 'Multiple', 'Multiple triggers initiating a process.', '2020-01-01 00:00:00', '2020-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_event` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (11, 'Parallel Multiple', 'A process instance that doesn\'t start, continue, or end until all possible events have occurred.', '2020-01-01 00:00:00', '2020-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_event` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (12, 'Terminate', 'Triggers the immediate termination of a process step. All related instances are terminated at the same time.', '2020-01-01 00:00:00', '2020-01-01 00:00:00');

COMMIT;


-- -----------------------------------------------------
-- Data for table `1office_0_2`.`bpmn_activity`
-- -----------------------------------------------------
START TRANSACTION;
USE `1office_0_2`;
INSERT INTO `1office_0_2`.`bpmn_activity` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (1, 'Task', 'The most basic level of an activity and cannot be broken down further. For example, a morning routine process might involve the task of turning on your computer.', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_activity` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (2, 'Sub-process', 'Is a group of tasks that fit together particularly well. There are two different views of the sub-process. One is the collapsed view, which has an expandable plus sign to show more details. The other view is an expanded sub-process view, which is large enough to house all the tasks that fully describe the sub-process.', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_activity` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (3, 'Transaction', 'Is a specialized sub-process that involves payment.', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_activity` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (4, 'Call', 'Is a global sub-process that is reused at various points in the business flow.', '2000-01-01 00:00:00', '2000-01-01 00:00:00');

COMMIT;


-- -----------------------------------------------------
-- Data for table `1office_0_2`.`bpmn_gateway`
-- -----------------------------------------------------
START TRANSACTION;
USE `1office_0_2`;
INSERT INTO `1office_0_2`.`bpmn_gateway` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (1, 'Exclusive', 'Evaluates the state of the business process and, based on the condition, breaks the flow into one or more mutually exclusive paths.', '2000-01-01- 00:00:00', '2000-01-01- 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_gateway` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (2, 'Event-based', 'An event-based gateway is similar to an exclusive gateway—both involve one path in the flow. In the case of an event-based gateway, however, you are evaluating which event has occurred, not which condition is being met.', '2000-01-01- 00:00:00', '2000-01-01- 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_gateway` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (3, 'Parallel', 'Differs from other gateways because it’s not dependent on conditions or events. Instead, parallel gateways are used to represent two concurrent tasks in a business flow.', '2000-01-01- 00:00:00', '2000-01-01- 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_gateway` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (4, 'Inclusive', 'Breaks the process flow into one or more flows.', '2000-01-01- 00:00:00', '2000-01-01- 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_gateway` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (5, 'Exclusive Event-based', 'Starts a new process instance with each occurrence of a subsequent event.', '2000-01-01- 00:00:00', '2000-01-01- 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_gateway` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (6, 'Complex', 'These gateways are only used for the most complex flows in a business process. An ideal use case for the complex gateway is when you need multiple gateways to describe the business flow.', '2000-01-01- 00:00:00', '2000-01-01- 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_gateway` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (7, 'Parallel Event-based', 'As the name suggests, this gateway is similar to a parallel gateway. It allows for multiple processes to happen at the same time, but unlike the parallel gateway, processes are event-dependent.', '2000-01-01- 00:00:00', '2000-01-01- 00:00:00');

COMMIT;


-- -----------------------------------------------------
-- Data for table `1office_0_2`.`bpmn_connection`
-- -----------------------------------------------------
START TRANSACTION;
USE `1office_0_2`;
INSERT INTO `1office_0_2`.`bpmn_connection` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (1, 'Sequence flow', 'Connects flow objects in proper sequential order.', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_connection` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (2, 'Message flow', 'Represents messages from one process participant to another.', '2000-01-01 00:00:00', '2000-01-01 00:00:00');
INSERT INTO `1office_0_2`.`bpmn_connection` (`id`, `name`, `description`, `created_at`, `updated_at`) VALUES (3, 'Association', 'Shows relationships between artifacts and flow objects.', '2000-01-01 00:00:00', '2000-01-01 00:00:00');

COMMIT;


